// Check each asset for significant price changes
const items = $input.all();
const alerts = [];
const threshold = 5; // 5% threshold

for (const item of items) {
  const data = item.json;
  const changePct = parseFloat(data.change_pct) || 0;

  if (Math.abs(changePct) >= threshold) {
    const direction = changePct > 0 ? 'spiked' : 'dropped';
    const emoji = changePct > 0 ? '📈' : '📉';
    const severity = Math.abs(changePct) >= 10 ? 'critical' : 'warning';

    alerts.push({
      json: {
        symbol: data.symbol,
        current_price: parseFloat(data.current_price),
        prev_price: parseFloat(data.prev_price),
        change_pct: changePct,
        direction: direction,
        emoji: emoji,
        severity: severity,
        message: `${emoji} *${data.symbol.toUpperCase()}* ${direction} *${Math.abs(changePct).toFixed(2)}%* to $${parseFloat(data.current_price).toLocaleString()}`,
        should_alert: true
      }
    });
  }
}

// If no alerts, return a no-op item
if (alerts.length === 0) {
  return [{ json: { should_alert: false, message: 'No significant price changes' } }];
}

return alerts;

// Log that no alert was needed
console.log('No significant price changes detected');
return $input.all();
